  'cursor':     { trend: 'up',     detailLink: 'https://www.cursor.com' },
  'notion-ai':  { trend: 'stable', detailLink: 'https://www.notion.com/product/ai' },
  'sora':       { trend: 'stable', detailLink: 'https://sora.com' },
  'perplexity': { trend: 'up',     detailLink: 'https://www.perplexity.ai' },
  'claude-code':{ trend: 'up',     detailLink: 'https://claude.ai/code' },
};

